class Solution:
    def numOfSubarrays(self, arr):
        MOD = 10 ** 9 + 7
        n = len(arr)
        count = 0
        for i in range(n):
            s = 0
            for j in range(i, n):
                s += arr[j]
                if s % 2 == 1:
                    count += 1
        return count % MOD

solutions.python:
class Solution:
    def numOfSubarrays(self, arr):
        MOD = 10 ** 9 + 7
        even = 1
        odd = 0
        running = 0
        ans = 0
        for x in arr:
            running ^= x % 2
            if running == 1:
                ans += even
                odd += 1
            else:
                ans += odd
                even += 1
        return ans % MOD

