var numOfSubarrays = function(arr) {
    const MOD = 1000000007;
    let even = 1, odd = 0, running = 0, ans = 0;
    for (const x of arr) {
        running ^= (x % 2);
        if (running === 1) {
            ans += even;
            odd += 1;
        } else {
            ans += odd;
            even += 1;
        }
    }
    return ans % MOD;
};
